const sc = $('ScrapeCreators').first().json || {};
const list = (sc.search_item_list||[]).map(it=>{const a=it.aweme_info||{};return {d:(a.desc||'').trim(),v:(a.statistics||{}).play_count||0};}).filter(x=>x.d).sort((a,b)=>b.v-a.v).slice(0,8);
const signals = list.map((r,i)=>`${i+1}. [${r.v.toLocaleString('ru-RU')}] ${r.d}`).join('\n') || '(нет данных)';
let trends='(нет)';
try{ trends = $('Perplexity').first().json.choices[0].message.content; }catch(e){}
return [{ json: { signals_text: signals, trends_text: trends } }];

const raw=$input.first().json.candidates[0].content.parts[0].text;
const idea=JSON.parse(raw.trim().replace(/^```json/i,'').replace(/^```/,'').replace(/```$/,'').trim());
const t=+idea.trend_score||0,u=+idea.usefulness_score||0,v=+idea.viral_score||0,pf=+idea.product_fit_score||0;
idea.total=+(t*0.2+u*0.3+v*0.25+pf*0.25).toFixed(2);
const s=(idea.topic||'').toLowerCase().replace(/[^0-9a-zа-яё ]/gi,'').replace(/\s+/g,' ').trim();
let h=5381; for(let i=0;i<s.length;i++){h=(((h<<5)+h)+s.charCodeAt(i))&0xffffffff;}
idea.topic_hash='h'+(h>>>0).toString(16);
idea.start_code='YT'+(h>>>0).toString(16).toUpperCase().slice(0,6);
return [{ json: idea }];

const idea=$('Parse idea').first().json;
const raw=$input.first().json.candidates[0].content.parts[0].text;
const concept=JSON.parse(raw.trim().replace(/^```json/i,'').replace(/^```/,'').replace(/```$/,'').trim());
const rt=v=>({rich_text:[{text:{content:String(v==null?'':v).slice(0,1900)}}]});
const link='https://t.me/foodgenius_ai_bot?start=ref_'+idea.start_code;
const caption=(concept.caption||idea.topic)+'\n\n'+(concept.cta||'')+' '+link;
const props={
  'title':{title:[{text:{content:String(idea.topic||'без темы').slice(0,1900)}}]},
  'status':{select:{name:'Needs Review'}},
  'platform':{select:{name:'youtube'}},
  'content_format':rt('video/shorts'),
  'post_text':rt(concept.hook_text||''),
  'final_text':rt(JSON.stringify(concept)),
  'cta':rt(concept.cta||''),
  'start_code':rt(idea.start_code),
  'target_audience':{select:{name:String(idea.audience_segment||'занятые').split('|')[0].trim()}},
  'post_hash':rt(idea.topic_hash),
  'created_at':{date:{start:new Date().toISOString()}},
  'updated_at':{date:{start:new Date().toISOString()}}
};
return [{ json: { topic: idea.topic, total: idea.total, start_code: idea.start_code, caption, notion_props: props } }];
